import React from "react";
import styled from "styled-components";
import Intro from "../intro/Intro";
import { NavLink } from "react-router-dom";

function Jumbotron() {
  return (
    <Container>
      <Intro />
      <Nav>
        <img src="https://i.ibb.co/r5krrdz/logo.png" alt="logo" />
        <NavLink to="/home">
          <NavButton>Home</NavButton>
        </NavLink>
      </Nav>
      <Content>
        <h1>
          Unlimited movies,TV <br />
          shows,and more.
        </h1>
        <h4>Watch anywhere. Cancel anytime.</h4>
        <p>
          Ready to watch? Enter your email to create or restart your membership.
        </p>
        <Input>
          <input
            type="text"
            placeholder="Email address
"
          />
          <span>Get Started</span>
        </Input>
      </Content>
    </Container>
  );
}

export default Jumbotron;

const Container = styled.div`
  width: 100%;
  height: 100vh;
  position: relative;
  background: url("/images/misc/home-bg.jpg");
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;

  &:before {
    content: "";
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0;
    left: 0;
    background: rgba(0, 0, 0, 0.3);
  }
`;

const Nav = styled.nav`
  position: absolute;
  top: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  padding: 2% 5%;
  transform: translateY(-100%);
  animation: top 1s linear forwards;
  animation-delay: 4s;

  @keyframes top {
    100% {
      transform: translateY(0%);
    }
  }


  }
  img {
    width: 180px;
    height: 40px;
  }
`;

const NavButton = styled.button`
  background-color: #e50914;

  padding: 7px 17px;
  font-weight: 400;
  font-size: 18px;
  color: #fff;
  border: 0;
  outline: 0;
  border-radius: 6px;
  cursor: pointer;
`;

const Content = styled.div`
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #fff;

  opacity: 0;
  animation: opacity 3s linear forwards;
  animation-delay: 3s;

  @keyframes opacity {
    100% {
      opacity: 1;
    }
  }

  h1 {
    font-size: 70px;
    margin-bottom: 10px;
    text-align: center;
    @media (max-width: 700px) {
      font-size: 25px;
      text-align: center;
    }
  }

  h4 {
    text-align: center;
    font-size: 20px;
    margin-bottom: 15px;
    @media (max-width: 700px) {
      font-size: 15px;
    }
  }

  p {
    text-align: center;
    font-size: 20px;
    margin-bottom: 30px;
    @media (max-width: 700px) {
      font-size: 10px;
    }
  }
`;

const Input = styled.div`
  display: flex;
  align-items: center;

  opacity: 0;
  animation: opacity 2s linear forwards;
  animation-delay: 3.2s;

  @media (max-width: 700px) {
    flex-direction: column;
  }

  input {
    flex: 1;
    padding: 20px;
    border: 0;
    outline: 0;
    position: relative;
    @media (max-width: 700px) {
      width: 100%;
    }
  }

  span {
    background-color: #e50914;
    padding: 19px;
    position: absolute;
    right: 0;
    display: block;
    font-size: 20px;
    @media (max-width: 700px) {
      bottom: -35%;
      left: 0;
      text-align: center;
    }
  }
`;
